type ModInviteUtilsProxy struct {
	utilities.UnimplementedModInviteUtilsServer
	client utilities.ModInviteUtilsClient
}

func init() {
	proxyutil.Register(&utilities.ModInviteUtils_ServiceDesc, NewModInviteUtilsProxy)
}
func NewModInviteUtilsProxy(cc grpc.ClientConnInterface) utilities.ModInviteUtilsServer {
	return &ModInviteUtilsProxy{client: utilities.NewModInviteUtilsClient(cc)}
}
func (p *ModInviteUtilsProxy) AcceptInvite(ctx context.Context, in *utilities.AcceptInviteRequest) (*utilities.AcceptInviteResponse, error) {
	return proxyutil.ProxyMethod[utilities.AcceptInviteRequest, utilities.AcceptInviteResponse](p.client.AcceptInvite)(ctx, in)
}
